/* eslint-disable @typescript-eslint/no-unused-vars, @typescript-eslint/no-explicit-any, react/no-unescaped-entities */
"use client";

import React, { useState } from "react";
import { 
  Trash2, 
  Edit,
  Loader2
} from "lucide-react";
import Link from "next/link";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import { deleteClient } from "@/server/actions/client.actions";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface ClientActionsProps {
  clientId: string;
  boutiqueId: string;
  clientNom: string;
}

export function ClientActions({ clientId, boutiqueId, clientNom }: ClientActionsProps) {
  const [isDeleting, setIsDeleting] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  const handleDelete = async () => {
    setIsDeleting(true);
    try {
      const result = await deleteClient({ clientId, boutiqueId });
      if (result?.data?.success) {
        toast.success(`Le client "${clientNom}" a été supprimé.`);
      } else {
        toast.error("Une erreur est survenue lors de la suppression.");
      }
    } catch {
      toast.error("Une erreur est survenue.");
    } finally {
      setIsDeleting(false);
      setShowDeleteDialog(false);
    }
  };

  return (
    <div className="flex items-center justify-end gap-2">
      <Button asChild variant="ghost" size="icon" className="h-10 w-10 rounded-xl hover:bg-zinc-100 dark:hover:bg-zinc-800">
        <Link href={`/boutiques/${boutiqueId}/clients/${clientId}/edit`}>
          <Edit className="h-4 w-4" />
        </Link>
      </Button>

      <Button 
        variant="ghost" 
        size="icon" 
        className="h-10 w-10 rounded-xl hover:bg-rose-50 text-rose-500 hover:text-rose-600 dark:hover:bg-rose-950"
        onClick={() => setShowDeleteDialog(true)}
      >
        <Trash2 className="h-4 w-4" />
      </Button>

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent className="rounded-[2.5rem] border-none shadow-2xl">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-2xl font-black tracking-tight">Supprimer ce client ?</AlertDialogTitle>
            <AlertDialogDescription className="font-medium text-muted-foreground">
              Êtes-vous sûr de vouloir supprimer "{clientNom}" ? Cette action est irréversible et supprimera l&apos;historique des commandes liées à ce client.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter className="gap-2">
            <AlertDialogCancel className="rounded-xl h-12 font-bold border-none bg-zinc-100 hover:bg-zinc-200">Annuler</AlertDialogCancel>
            <AlertDialogAction 
              onClick={(e) => {
                e.preventDefault();
                handleDelete();
              }}
              className="rounded-xl h-12 font-black bg-rose-500 hover:bg-rose-600 shadow-lg shadow-rose-500/20"
              disabled={isDeleting}
            >
              {isDeleting ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : null}
              Confirmer la suppression
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-unused-vars, @typescript-eslint/no-explicit-any, react/no-unescaped-entities */
"use client";

import { useState, use } from "react";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { toast } from "sonner";
import { 
// eslint-disable-next-line @typescript-eslint/no-unused-vars
  User, 
  ArrowLeft, 
  Save, 
  Phone, 
  Mail, 
  MapPin, 
  Loader2 
} from "lucide-react";
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { motion } from "framer-motion";
import Link from "next/link";

import { createClient } from "@/server/actions/client.actions";
import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";

const clientSchema = z.object({
  nom: z.string().min(1, "Le nom est requis"),
  prenom: z.string().optional().or(z.literal("")),
  telephone: z.string().optional().or(z.literal("")),
  email: z.string().email("Email invalide").optional().or(z.literal("")),
  adresse: z.string().optional().or(z.literal("")),
});

interface NewClientPageProps {
  params: Promise<{ id: string }>;
}

export default function NewClientPage({ params }: NewClientPageProps) {
  const { id: boutiqueId } = use(params);
  const router = useRouter();
  const [loading, setLoading] = useState(false);

  const form = useForm<z.infer<typeof clientSchema>>({
    resolver: zodResolver(clientSchema),
    defaultValues: {
      nom: "",
      prenom: "",
      telephone: "",
      email: "",
      adresse: "",
    },
  });

  async function onSubmit(data: z.infer<typeof clientSchema>) {
    setLoading(true);
    try {
      const result = await createClient({
        boutiqueId,
        ...data,
// eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any);

      if (result?.serverError) {
        toast.error(result.serverError);
        return;
      }

      toast.success("Client ajouté avec succès !");
      router.push(`/boutiques/${boutiqueId}/clients`);
      router.refresh();
    } catch {
      toast.error("Une erreur est survenue.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="mx-auto max-w-2xl py-8 px-4">
      <div className="mb-8 flex items-center gap-4">
        <Button asChild variant="ghost" className="rounded-full h-12 w-12 p-0">
          <Link href={`/boutiques/${boutiqueId}/clients`}>
            <ArrowLeft className="h-6 w-6" />
          </Link>
        </Button>
        <div>
          <h1 className="text-3xl font-black tracking-tight">Nouveau Client</h1>
          <p className="text-muted-foreground font-medium">Ajoutez un client à votre base de données.</p>
        </div>
      </div>

      <Card className="border-none bg-white dark:bg-zinc-900 shadow-2xl rounded-[3rem] overflow-hidden">
        <CardHeader className="p-8 pb-4">
          <CardTitle className="text-xl font-black">Informations Personnelles</CardTitle>
          <CardDescription className="font-bold">Saisissez les détails du client pour faciliter le suivi.</CardDescription>
        </CardHeader>
        <CardContent className="p-8 pt-4">
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
              <div className="grid gap-6 md:grid-cols-2">
                <FormField
                  control={form.control}
                  name="prenom"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Prénom</FormLabel>
                      <FormControl>
                        <Input placeholder="Prénom" className="h-12 rounded-xl bg-zinc-50 dark:bg-zinc-800 border-none px-4 font-bold" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="nom"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-[10px] font-black uppercase tracking-widest text-muted-foreground">Nom *</FormLabel>
                      <FormControl>
                        <Input placeholder="Nom de famille" className="h-12 rounded-xl bg-zinc-50 dark:bg-zinc-800 border-none px-4 font-bold" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <div className="grid gap-6 md:grid-cols-2">
                <FormField
                  control={form.control}
                  name="telephone"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-[10px] font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                        <Phone className="h-3 w-3" /> Téléphone
                      </FormLabel>
                      <FormControl>
                        <Input placeholder="+221 ..." className="h-12 rounded-xl bg-zinc-50 dark:bg-zinc-800 border-none px-4 font-bold" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="email"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="text-[10px] font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                        <Mail className="h-3 w-3" /> Email
                      </FormLabel>
                      <FormControl>
                        <Input type="email" placeholder="client@email.com" className="h-12 rounded-xl bg-zinc-50 dark:bg-zinc-800 border-none px-4 font-bold" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>

              <FormField
                control={form.control}
                name="adresse"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel className="text-[10px] font-black uppercase tracking-widest text-muted-foreground flex items-center gap-2">
                      <MapPin className="h-3 w-3" /> Adresse
                    </FormLabel>
                    <FormControl>
                      <Input placeholder="Quartier, Ville" className="h-12 rounded-xl bg-zinc-50 dark:bg-zinc-800 border-none px-4 font-bold" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <Button 
                type="submit" 
                variant="brand" 
                size="xl" 
                className="w-full h-14 rounded-2xl font-black text-lg shadow-xl shadow-brand/20"
                disabled={loading}
              >
                {loading ? (
                  <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                ) : (
                  <Save className="mr-2 h-5 w-5" />
                )}
                Enregistrer le client
              </Button>
            </form>
          </Form>
        </CardContent>
      </Card>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-unused-vars, @typescript-eslint/no-explicit-any, react/no-unescaped-entities */
import React from "react";
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { Plus, Users, Search, Phone, Mail, MapPin, Trash2, Edit } from "lucide-react";
import { redirect } from "next/navigation";

import { auth } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ClientActions } from "./_components/client-actions";
import Link from "next/link";

interface ClientsPageProps {
  params: Promise<{ id: string }>;
}

export default async function ClientsPage({ params }: ClientsPageProps) {
  const { id: boutiqueId } = await params;
  const session = await auth();
  if (!session?.user) redirect("/login");

  const clients = await prisma.client.findMany({
    where: { boutiqueId },
    orderBy: { nom: "asc" },
  });

  return (
    <div className="space-y-8">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-3xl font-black tracking-tight">Clients</h1>
          <p className="text-muted-foreground font-medium">Gérez votre base de clients et leur historique.</p>
        </div>
        <Button asChild variant="brand" className="rounded-xl h-12 px-6 font-black shadow-lg shadow-brand/20">
          <Link href={`/boutiques/${boutiqueId}/clients/new`}>
            <Plus className="mr-2 h-5 w-5" />
            Nouveau Client
          </Link>
        </Button>
      </div>

      <Card className="border-none shadow-xl rounded-[2.5rem] bg-white dark:bg-zinc-900 overflow-hidden">
        <CardHeader className="p-8 pb-4">
          <div className="relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
            <Input 
              placeholder="Rechercher un client..." 
              className="pl-12 h-14 rounded-2xl bg-zinc-50 dark:bg-zinc-800 border-none font-bold"
            />
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <Table>
            <TableHeader className="bg-zinc-50 dark:bg-zinc-800/50">
              <TableRow className="border-none">
                <TableHead className="px-8 py-5 font-black uppercase text-[10px] tracking-widest">Client</TableHead>
                <TableHead className="py-5 font-black uppercase text-[10px] tracking-widest">Contact</TableHead>
                <TableHead className="py-5 font-black uppercase text-[10px] tracking-widest">Adresse</TableHead>
                <TableHead className="py-5 font-black uppercase text-[10px] tracking-widest text-right px-8">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {clients.length > 0 ? (
                clients.map((client) => (
                  <TableRow key={client.id} className="border-zinc-50 dark:border-zinc-800 hover:bg-zinc-50/50 dark:hover:bg-zinc-800/50 transition-colors group">
                    <TableCell className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <div className="h-12 w-12 rounded-2xl bg-brand/10 flex items-center justify-center text-brand font-black text-lg">
                          {(client.prenom?.[0] || "") + (client.nom?.[0] || "")}
                        </div>
                        <div>
                          <p className="font-black text-base">{client.prenom} {client.nom}</p>
                          <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Client Fidèle</p>
                        </div>
                      </div>
                    </TableCell>
                    <TableCell className="py-6">
                      <div className="space-y-1">
                        {client.telephone && (
                          <div className="flex items-center gap-2 text-sm font-bold">
                            <Phone className="h-3 w-3 text-emerald-500" />
                            {client.telephone}
                          </div>
                        )}
                        {client.email && (
                          <div className="flex items-center gap-2 text-sm font-bold text-muted-foreground">
                            <Mail className="h-3 w-3 text-brand" />
                            {client.email}
                          </div>
                        )}
                      </div>
                    </TableCell>
                    <TableCell className="py-6">
                      {client.adresse ? (
                        <div className="flex items-center gap-2 text-sm font-bold text-muted-foreground">
                          <MapPin className="h-3 w-3 text-amber-500" />
                          {client.adresse}
                        </div>
                      ) : (
                        <span className="text-zinc-300 dark:text-zinc-700 italic text-sm">Non spécifiée</span>
                      )}
                    </TableCell>
                    <TableCell className="px-8 py-6 text-right">
                      <ClientActions 
                        clientId={client.id} 
                        boutiqueId={boutiqueId} 
                        clientNom={`${client.prenom || ""} ${client.nom}`} 
                      />
                    </TableCell>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={4} className="h-64 text-center">
                    <div className="flex flex-col items-center justify-center space-y-4">
                      <div className="h-20 w-20 rounded-full bg-zinc-50 dark:bg-zinc-800 flex items-center justify-center">
                        <Users className="h-10 w-10 text-muted-foreground" />
                      </div>
                      <div>
                        <p className="text-xl font-black">Aucun client trouvé</p>
                        <p className="text-muted-foreground font-medium">Commencez par ajouter votre premier client.</p>
                      </div>
                      <Button asChild variant="brand" className="rounded-xl h-12 px-8 font-black">
                        <Link href={`/boutiques/${boutiqueId}/clients/new`}>Ajouter un client</Link>
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}

/* eslint-disable @typescript-eslint/no-unused-vars, @typescript-eslint/no-explicit-any, react/no-unescaped-entities */
"use client";

import { useState } from "react";
import { useRouter, useParams } from "next/navigation";
import { toast } from "sonner";
import { Plus, Minus, Trash2, ShoppingCart, Loader2 } from "lucide-react";
import { createCommandeClient } from "@/server/actions/commande.actions";
import { formatCurrency } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";

interface CartItem {
  produitId: string;
  nom: string;
  prixUnitaire: number;
  quantite: number;
}

export default function NouvelleCommandePage() {
  const router = useRouter();
  const params = useParams<{ id: string }>();
  const boutiqueId = params.id;
  const [cart, setCart] = useState<CartItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [notes, setNotes] = useState("");

  // In production, this would fetch from API
// eslint-disable-next-line @typescript-eslint/no-unused-vars
  function addToCart(produit: { id: string; nom: string; prixUnitaire: number }) {
    setCart((prev) => {
      const existing = prev.find((item) => item.produitId === produit.id);
      if (existing) {
        return prev.map((item) =>
          item.produitId === produit.id ? { ...item, quantite: item.quantite + 1 } : item
        );
      }
      return [...prev, { produitId: produit.id, nom: produit.nom, prixUnitaire: produit.prixUnitaire, quantite: 1 }];
    });
  }

  function updateQuantite(produitId: string, delta: number) {
    setCart((prev) =>
      prev
        .map((item) =>
          item.produitId === produitId ? { ...item, quantite: Math.max(0, item.quantite + delta) } : item
        )
        .filter((item) => item.quantite > 0)
    );
  }

  function removeItem(produitId: string) {
    setCart((prev) => prev.filter((item) => item.produitId !== produitId));
  }

  const total = cart.reduce((sum, item) => sum + item.prixUnitaire * item.quantite, 0);

  async function handleSubmit() {
    if (cart.length === 0) {
      toast.error("Ajoutez au moins un produit");
      return;
    }

    setLoading(true);
    try {
      const result = await createCommandeClient({
        boutiqueId,
        data: {
          notes: notes || undefined,
          lignes: cart.map((item) => ({
            produitId: item.produitId,
            quantite: item.quantite,
            prixUnitaire: item.prixUnitaire,
          })),
        },
      });

      if (result?.serverError) {
        toast.error(result.serverError);
        return;
      }

      toast.success("Commande créée avec succès !");
      router.push(`/boutiques/${boutiqueId}/commandes`);
      router.refresh();
    } catch {
      toast.error("Erreur lors de la création");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold tracking-tight">Nouvelle commande</h1>
      <p className="text-sm text-muted-foreground">Créez une commande client</p>

      <div className="mt-6 grid gap-6 lg:grid-cols-3">
        {/* Product Search */}
        <div className="lg:col-span-2 space-y-4">
          <Input
            placeholder="Rechercher un produit..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <p className="text-sm text-muted-foreground">
            Recherchez et ajoutez des produits au panier.
          </p>
        </div>

        {/* Cart */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2 text-base">
              <ShoppingCart className="h-4 w-4" /> Panier ({cart.length})
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {cart.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-4">
                Le panier est vide
              </p>
            ) : (
              cart.map((item) => (
                <div key={item.produitId} className="flex items-center justify-between text-sm">
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate">{item.nom}</p>
                    <p className="text-muted-foreground">{formatCurrency(item.prixUnitaire)}</p>
                  </div>
                  <div className="flex items-center gap-1">
                    <Button variant="outline" size="icon" className="h-7 w-7" onClick={() => updateQuantite(item.produitId, -1)}>
                      <Minus className="h-3 w-3" />
                    </Button>
                    <span className="w-8 text-center">{item.quantite}</span>
                    <Button variant="outline" size="icon" className="h-7 w-7" onClick={() => updateQuantite(item.produitId, 1)}>
                      <Plus className="h-3 w-3" />
                    </Button>
                    <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive" onClick={() => removeItem(item.produitId)}>
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  </div>
                </div>
              ))
            )}

            {cart.length > 0 && (
              <>
                <Separator />
                <div className="flex justify-between font-bold">
                  <span>Total</span>
                  <span>{formatCurrency(total)}</span>
                </div>
              </>
            )}

            <Input
              placeholder="Notes (optionnel)"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
          </CardContent>
          <CardFooter>
            <Button className="w-full" disabled={cart.length === 0 || loading} onClick={handleSubmit}>
              {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Valider la commande
            </Button>
          </CardFooter>
        </Card>
      </div>
    </div>
  );
}

