"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { toast } from "sonner";
import { Plus, Search, MoreHorizontal, Pencil, Trash2, Truck } from "lucide-react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { createFournisseurSchema, type CreateFournisseurInput } from "@/schemas/fournisseur.schema";
import { createFournisseur, deleteFournisseur } from "@/server/actions/fournisseur.actions";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from "@/components/ui/sheet";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { ConfirmDialog } from "@/components/confirm-dialog";
import { EmptyState } from "@/components/empty-state";

interface Fournisseur {
  id: string; nom: string; telephone: string | null; email: string | null; adresse: string | null;
  _count: { commandes: number };
}

// eslint-disable-next-line @typescript-eslint/no-unused-vars
export function FournisseursClient({ fournisseurs, boutiqueId, total }: { fournisseurs: Fournisseur[]; boutiqueId: string; total: number }) {
  const router = useRouter();
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");

  const form = useForm<CreateFournisseurInput>({
    resolver: zodResolver(createFournisseurSchema),
    defaultValues: { nom: "", telephone: "", email: "", adresse: "" },
  });

  const filtered = fournisseurs.filter((f) => f.nom.toLowerCase().includes(search.toLowerCase()));

  async function onSubmit(data: CreateFournisseurInput) {
    const result = await createFournisseur({ boutiqueId, ...data });
    if (result?.serverError) { toast.error(result.serverError); return; }
    toast.success("Fournisseur créé");
    form.reset(); setOpen(false); router.refresh();
  }

  async function handleDelete(fournisseurId: string) {
    const result = await deleteFournisseur({ boutiqueId, fournisseurId });
    if (result?.serverError) { toast.error(result.serverError); return; }
    toast.success("Fournisseur supprimé"); router.refresh();
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-4">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input placeholder="Rechercher..." value={search} onChange={(e) => setSearch(e.target.value)} className="pl-10" />
        </div>
        <Sheet open={open} onOpenChange={setOpen}>
          <SheetTrigger asChild><Button><Plus className="mr-2 h-4 w-4" /> Ajouter</Button></SheetTrigger>
          <SheetContent>
            <SheetHeader><SheetTitle>Nouveau fournisseur</SheetTitle></SheetHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="mt-6 space-y-4">
                <FormField control={form.control} name="nom" render={({ field }) => (<FormItem><FormLabel>Nom</FormLabel><FormControl><Input {...field} /></FormControl><FormMessage /></FormItem>)} />
                <FormField control={form.control} name="telephone" render={({ field }) => (<FormItem><FormLabel>Téléphone</FormLabel><FormControl><Input {...field} /></FormControl><FormMessage /></FormItem>)} />
                <FormField control={form.control} name="email" render={({ field }) => (<FormItem><FormLabel>Email</FormLabel><FormControl><Input type="email" {...field} /></FormControl><FormMessage /></FormItem>)} />
                <FormField control={form.control} name="adresse" render={({ field }) => (<FormItem><FormLabel>Adresse</FormLabel><FormControl><Input {...field} /></FormControl><FormMessage /></FormItem>)} />
                <Button type="submit" className="w-full">Créer</Button>
              </form>
            </Form>
          </SheetContent>
        </Sheet>
      </div>
      {filtered.length === 0 && !search ? (
        <EmptyState icon={Truck} title="Aucun fournisseur" description="Ajoutez vos premiers fournisseurs." />
      ) : (
        <div className="rounded-md border">
          <Table>
            <TableHeader><TableRow><TableHead>Nom</TableHead><TableHead>Téléphone</TableHead><TableHead>Email</TableHead><TableHead>Commandes</TableHead><TableHead className="w-10" /></TableRow></TableHeader>
            <TableBody>
              {filtered.map((f) => (
                <TableRow key={f.id}>
                  <TableCell className="font-medium">{f.nom}</TableCell>
                  <TableCell>{f.telephone || "—"}</TableCell><TableCell>{f.email || "—"}</TableCell><TableCell>{f._count.commandes}</TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild><Button variant="ghost" size="icon" className="h-8 w-8"><MoreHorizontal className="h-4 w-4" /></Button></DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuItem><Pencil className="mr-2 h-4 w-4" /> Modifier</DropdownMenuItem>
                        <ConfirmDialog trigger={<DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive"><Trash2 className="mr-2 h-4 w-4" /> Supprimer</DropdownMenuItem>} title="Supprimer ce fournisseur ?" description="Les commandes associées seront conservées." onConfirm={() => handleDelete(f.id)} />
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </div>
      )}
    </div>
  );
}

