            Créer une boutique
          </Link>
        </Button>
      </div>

      {/* Grid des Boutiques */}
      <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
        {boutiques.length > 0 ? (
          boutiques.map((boutique) => (
            <Card key={boutique.id} className="group border-none bg-white dark:bg-zinc-900 shadow-xl hover:shadow-2xl transition-all duration-300 rounded-[3rem] overflow-hidden flex flex-col">
