                    <Store className="h-8 w-8" />
                  </div>
                  <Badge variant="outline" className="border-emerald-500/20 text-emerald-500 font-black uppercase text-[9px] px-2 py-0.5">Actif</Badge>
                </div>
                <CardTitle className="text-2xl font-black tracking-tight group-hover:text-brand transition-colors">{boutique.nom}</CardTitle>
                <CardDescription className="font-bold text-sm line-clamp-1">{boutique.secteurActivite || "Secteur non défini"}</CardDescription>
