                  <Button asChild variant="brand" className="flex-1 h-12 rounded-xl font-black shadow-lg shadow-brand/10">
                    <Link href={`/boutiques/${boutique.id}`}>
                      Dashboard <LayoutDashboard className="ml-2 h-4 w-4" />
                    </Link>
                  </Button>
                  <Button asChild variant="outline" size="icon" className="h-12 w-12 rounded-xl border-2 hover:bg-zinc-100 dark:hover:bg-zinc-800">
                    <Link href={`/boutiques/${boutique.id}/parametres`}>
                      <Settings className="h-5 w-5" />
                    </Link>
                  </Button>
                </div>
              </CardContent>
            </Card>
          ))
