          <Card className="col-span-full border-dashed border-2 border-zinc-200 dark:border-zinc-800 bg-transparent rounded-[3rem] p-16 flex flex-col items-center text-center space-y-6">
            <div className="h-24 w-24 rounded-full bg-zinc-50 dark:bg-zinc-800 flex items-center justify-center">
              <Store className="h-12 w-12 text-muted-foreground" />
