import { updateProfile } from "@/server/actions/user.actions";

const profileSchema = z.object({
  name: z.string().min(2, "Le nom est trop court").max(100),
  image: z.string().url("URL d'image invalide").optional().or(z.literal("")),
});

export default function ProfilePage() {
  const { data: session, update } = useSession();
  const [loading, setLoading] = useState(false);

  const form = useForm<z.infer<typeof profileSchema>>({
    resolver: zodResolver(profileSchema),
    defaultValues: {
      name: session?.user?.name || "",
      image: session?.user?.image || "",
    },
  });

  async function onSubmit(values: z.infer<typeof profileSchema>) {
    setLoading(true);
    try {
      const result = await updateProfile(values);

      if (result?.serverError) {
        toast.error(result.serverError);
        return;
      }

      await update({
        ...session,
        user: {
          ...session?.user,
          name: values.name,
          image: values.image || null,
        },
      });

      toast.success("Profil mis à jour avec succès !");
// eslint-disable-next-line @typescript-eslint/no-unused-vars
    } catch (error) {
      toast.error("Une erreur est survenue.");
    } finally {
      setLoading(false);
    }
  }

  const name = session?.user?.name || "Utilisateur";
  const initials = getInitials(name);

  return (
    <div className="max-w-4xl mx-auto space-y-10 py-10">
      <div className="space-y-2">
