"use client";

import { Package, ShoppingCart } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { useCart } from "@/hooks/use-cart";
import { formatCurrency } from "@/lib/utils";
import { toast } from "sonner";

interface ProductCardProps {
  produit: {
    id: string;
    nom: string;
    prixUnitaire: number;
    quantite: number;
    photo: string | null;
    categorie: { nom: string } | null;
  };
  boutiqueSlug: string;
  boutiqueNom: string;
}

export function ProductCard({ produit, boutiqueSlug, boutiqueNom }: ProductCardProps) {
  const { addItem } = useCart();

  function handleAddToCart(e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();
    addItem({
      produitId: produit.id,
      boutiqueSlug,
      boutiqueNom,
      nom: produit.nom,
      prixUnitaire: produit.prixUnitaire,
      photo: produit.photo,
    });
    toast.success(`${produit.nom} ajouté au panier`);
  }

  return (
    <div className="flex flex-col h-full rounded-[2rem] border border-border bg-card/40 hover:border-brand/30 transition-all duration-500 hover:-translate-y-2 overflow-hidden shadow-sm hover:shadow-xl group">
      <div className="aspect-square bg-muted/30 flex items-center justify-center relative group-hover:bg-muted/50 transition-colors overflow-hidden">
        {produit.photo ? (
          <img
            src={produit.photo}
            alt={produit.nom}
            className="h-full w-full object-cover transition-transform duration-500 group-hover:scale-110"
          />
        ) : (
          <Package className="h-16 w-16 text-foreground/10 group-hover:scale-110 transition-transform duration-500" />
        )}
        <div className="absolute top-4 right-4">
          <Badge
            variant={produit.quantite > 0 ? "success" : "destructive"}
            className="rounded-full px-3 font-bold text-[10px] uppercase tracking-widest"
          >
            {produit.quantite > 0 ? "Stock" : "Épuisé"}
          </Badge>
        </div>
      </div>
      <div className="p-6 flex flex-col flex-1">
        <h3 className="font-bold text-foreground mb-1 group-hover:text-brand transition-colors truncate">
          {produit.nom}
        </h3>
        {produit.categorie && (
          <p className="text-xs text-muted-foreground mb-3 font-medium">
            {produit.categorie.nom}
          </p>
        )}
        <div className="mt-auto flex items-center justify-between gap-2">
          <p className="text-xl font-black text-foreground tracking-tighter">
            {formatCurrency(produit.prixUnitaire)}
          </p>
          <Button
            size="sm"
            variant="brand"
            className="rounded-xl px-3 h-9 font-bold text-xs shadow-lg shadow-brand/10"
            onClick={handleAddToCart}
            disabled={produit.quantite <= 0}
          >
            <ShoppingCart className="h-3.5 w-3.5 mr-1.5" />
            Ajouter
          </Button>
        </div>
      </div>
    </div>
  );
}

