import { notFound } from "next/navigation";
import Link from "next/link";
// eslint-disable-next-line @typescript-eslint/no-unused-vars
import { ArrowLeft, Store, Package, Sparkles, Phone } from "lucide-react";
import { prisma } from "@/lib/prisma";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { formatCurrency } from "@/lib/utils";
import { AddToCartButton } from "./_components/add-to-cart-button";

type Props = {
  params: Promise<{ slug: string; id: string }>;
};

export default async function ProduitPublicPage({ params }: Props) {
  const { slug, id } = await params;

  // SECURITY: First resolve slug to boutique, then scope product query by boutiqueId
  const boutique = await prisma.boutique.findFirst({
    where: { slug, statut: "ACTIF" },
    select: { id: true, nom: true, slug: true, telephone: true },
  });

  if (!boutique) notFound();

  const produit = await prisma.produit.findFirst({
    where: { id, boutiqueId: boutique.id },
    include: { categorie: true },
  });

  if (!produit) notFound();

  return (
    <div className="container-app py-12 lg:py-20">
      <div className="mb-10">
        <Button asChild variant="ghost" className="rounded-xl font-bold group">
          <Link href={`/s/${slug}`}>
            <ArrowLeft className="mr-2 h-4 w-4 transition-transform group-hover:-translate-x-1" />
            Retour à {boutique.nom}
          </Link>
        </Button>
      </div>

      <div className="grid gap-12 lg:grid-cols-2">
        {/* Product Image Section */}
        <div className="relative group">
          <div className="absolute -inset-1 bg-gradient-to-r from-brand to-info opacity-10 blur-2xl rounded-[2.5rem]" />
          <div className="relative aspect-square rounded-[2.5rem] bg-card border border-border flex items-center justify-center overflow-hidden shadow-2xl">
            {produit.photo ? (
              <img
                src={produit.photo}
                alt={produit.nom}
                className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-110"
              />
            ) : (
              <Package className="h-32 w-32 text-foreground/5" />
            )}

            <div className="absolute top-6 left-6">
              <Badge variant="brand" className="rounded-full px-4 py-1.5 text-xs font-black uppercase tracking-widest shadow-lg shadow-brand/20">

                {produit.categorie?.nom || "Produit"}
              </Badge>
            </div>
          </div>
        </div>

        {/* Product Info Section */}
        <div className="flex flex-col">
          <div className="space-y-4 mb-8">
            <h1 className="text-display text-4xl md:text-6xl tracking-tight text-foreground">{produit.nom}</h1>
            <div className="flex items-center gap-4">
              <p className="text-4xl font-black text-brand tracking-tighter">
                {formatCurrency(produit.prixUnitaire)}
              </p>
              {produit.quantite > 0 ? (
                <div className="flex items-center gap-1.5 px-3 py-1 rounded-full bg-success/10 border border-success/20">
                  <span className="w-2 h-2 rounded-full bg-success" />
                  <span className="text-[10px] font-black text-success uppercase tracking-widest">En stock</span>
                </div>
              ) : (
                <div className="flex items-center gap-1.5 px-3 py-1 rounded-full bg-destructive/10 border border-destructive/20">
                  <span className="w-2 h-2 rounded-full bg-destructive" />
                  <span className="text-[10px] font-black text-destructive uppercase tracking-widest">Indisponible</span>
                </div>
              )}
            </div>
            <p className="text-sm font-bold text-muted-foreground uppercase tracking-widest">
              Référence: {produit.code}
            </p>
          </div>

          <Separator className="mb-8 opacity-50" />

          <div className="text-lg text-muted-foreground leading-relaxed mb-10 font-medium">
            {produit.description ? (
              <p className="whitespace-pre-line">{produit.description}</p>
            ) : (
              <p>
                Ce produit exceptionnel est proposé par <span className="text-foreground font-bold">{boutique.nom}</span>. 
                Profitez d&apos;une qualité garantie et d&apos;un service client irréprochable.
              </p>
            )}
          </div>

          {/* Order Actions Card */}
          <div className="glass rounded-[2rem] p-8 md:p-10 border border-white/5 shadow-2xl relative overflow-hidden">
            <div className="relative z-10">
              <h3 className="text-xl font-bold text-foreground mb-6 flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-brand" />
                Commander cet article
              </h3>

              <div className="space-y-4">
                <AddToCartButton
                  produit={{ id: produit.id, nom: produit.nom, prixUnitaire: produit.prixUnitaire, photo: produit.photo }}
                  boutiqueSlug={slug}
                  boutiqueNom={boutique.nom}
                  disabled={produit.quantite <= 0}
                />

                <Button asChild size="xl" variant="outline" className="w-full h-16 rounded-2xl font-black text-lg bg-white/5 border-white/10 hover:bg-white/10 transition-all">
                  <a href={`tel:${boutique.telephone}`}>
                    <Phone className="mr-3 h-5 w-5" />
                    Appeler la boutique
                  </a>
                </Button>
              </div>

              <p className="mt-6 text-center text-xs font-bold text-muted-foreground uppercase tracking-widest opacity-60">
